mapper.delete:
        DELETE
          FROM esg.tb_safety_duties_doc_user
		 WHERE doc_type = #{docType}
           AND write_year = #{writeYear}
           AND doc_no = #{docNo}
           AND doc_seq = #{docSeq}

UPDATE esg.tb_safety_duties_doc
   SET use_yn='N',
       updated_at = now(),
       updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_no = #{docNo}
   AND doc_type= #{docType}

mapper.update:
UPDATE esg.tb_safety_duties_doc_user
   SET appointment_dt = #{appointmentDt},
       dismissal_dt = #{dismissalDt},
       use_yn = #{useYn}
 WHERE doc_type=#{docType}
   and write_year=#{writeYear}
   and doc_no=#{docNo}
   and doc_seq=#{docSeq}

mapper.select:
   WITH codeList AS(
       SELECT comp_id, orgn_role_id as id, orgn_role_nm as nm, ord_seq, 'safety' as orgn_role_type
         FROM esg.tb_safety_health_org_chart_orgn_role
        WHERE comp_id = #{compId}
        UNION
       SELECT comp_id, orgn_role_id as id, orgn_role_nm as nm, ord_seq, 'risk' as orgn_role_type
         FROM esg.tb_risk_assessment_organ_chart_orgn_role traocor
        WHERE comp_id = #{compId}
        UNION
       SELECT comp_id, minor_cd as id, minor_nm as nm, ord_seq, 'common' as orgn_role_type
         FROM esg.tb_common_d
        WHERE major_cd = 'C0025'
   )
   SELECT a.*, b.nm as label
     FROM esg.tb_safety_duties_doc a
LEFT JOIN codeList b ON a.orgn_role_id = b.id AND a.orgn_role_type = b.orgn_role_type
    WHERE a.comp_id = #{compId}
      AND a.write_year = #{writeYear}
      AND a.doc_no = #{docNo}
 ORDER BY b.ord_seq desc

SELECT *
  FROM dataset.tb_dataset_safety_duties_doc
 WHERE orgn_role_id = #{orgnRoleId}
   AND orgn_role_type = #{orgnRoleType}
